@startuml
skinparam UMLSequenceDiagram {
    participant Actor
    participant Tumblebug
    participant Database
    participant Spider
    participant SpiderDB
}

participant Actor
participant Tumblebug
participant Database
participant Spider
participant SpiderDB

Actor as User
Tumblebug as Tumblebug
Database as tumblebug db
Spider as Spider
SpiderDB as spider db

User ->> Tumblebug: POST/driver {name, csp, driver}
Tumblebug ->> Spider: {driver}
Spider ->> SpiderDB: {driver}

User ->> Tumblebug: POST/region {name, csp, reigin, zone}
Tumblebug ->> Spider: {region}
Spider ->> SpiderDB: {region}

User ->> Tumblebug: POST/credential {name, csp, credentials}
Tumblebug ->> Spider: {credential}
Spider ->> SpiderDB: {credential}

User ->> Tumblebug: POST/connectionconfig {name, csp, driver, credential, region}
Tumblebug ->> Spider: {config}
Spider ->> SpiderDB: {config}

User ->> Tumblebug: POST/ns {name}
Tumblebug ->> Spider: {ns}
Spider ->> SpiderDB: {ns}
Spider ->> Tumblebug: {ns}

@enduml
